// Parámetros del query string (GET request)
const query = $json.query || {};
const servicio = (query.servicio || '').toLowerCase();
const fecha = query.fecha;

// Validación
if (!servicio || !fecha) {
  return [{ json: { ok: false, error: 'Parámetros servicio y fecha son requeridos', valid: false } }];
}
if (!['spa', 'restaurante'].includes(servicio)) {
  return [{ json: { ok: false, error: 'Servicio debe ser spa o restaurante', valid: false } }];
}

// Configuración por servicio
const config = {
  spa:         { intervalo: 60, aforo: 4,  inicio: [10, 0], fin: [20, 0] },
  restaurante: { intervalo: 30, aforo: 20, inicio: [12, 0], fin: [23, 0] }
};

const { intervalo, aforo, inicio, fin } = config[servicio];

// Generar todos los slots del día
const slots = [];
let mins = inicio[0] * 60 + inicio[1];
const finMins = fin[0] * 60 + fin[1];

while (mins < finMins) {
  const h = Math.floor(mins / 60);
  const m = mins % 60;
  slots.push(String(h).padStart(2, '0') + ':' + String(m).padStart(2, '0'));
  mins += intervalo;
}

return [{ json: { servicio, fecha, slots, aforo, valid: true } }];

// Recibir todas las reservas existentes para esta fecha/servicio
const reservas = $input.all();

// Recuperar los parámetros generados en el nodo anterior
const params = $('Generar Slots').first().json;
const { slots, aforo, servicio, fecha } = params;

// Calcular ocupación por slot (suma de personas)
const ocupacion = {};
for (const r of reservas) {
  const hora = r.json.hora;
  const pax = parseInt(r.json.personas, 10) || 1;
  if (hora) {
    ocupacion[hora] = (ocupacion[hora] || 0) + pax;
  }
}

// Devolver solo los slots con aforo disponible
const disponibles = slots.filter(s => (ocupacion[s] || 0) < aforo);

return [{ json: { ok: true, data: disponibles, servicio, fecha } }];
